a2c23396  //
3f346adf  // Plan 03-04 Task 2 (GREEN). Minimal Prometheus-text parser + HTTP GET
525cc703  // wrapper + sliding-window token-rate tracker for the vLLM /metrics endpoint.
a2c23396  //
9e047526  // RESEARCH-verified (2026-04-21 §Summary #3):
50785c1a  //   - KV cache metric is `vllm:gpu_cache_usage_perc` (Gauge, 0-1).
c2078582  //     CONTEXT D-22 transcribed the wrong name — `vllm:kv[ELIDED]cache_usage_perc`
2f770ec2  //     does NOT exist; planner must honor the verified name.
c5da447c  //   - Decode throughput comes from `vllm:generation_tokens_total` (Counter).
254d6d8a  //     A 5-sample sliding window over this Counter gives a smooth tok/s
0b8b2120  //     signal (Pitfall #6 — raw 1s delta is noisy because completions
03e5d868  //     bunch at request boundaries).
a2c23396  //
1782a571  // "Don't hand-roll" guidance from RESEARCH §STACK: a simple regex-based
a32e8ea1  // parser is sufficient for this endpoint — we only consume 2-3 metrics,
7b21f6dd  // and the Prometheus text format is trivial. Pulling in `prom-client`
04fc2929  // just to parse would add a dependency for zero benefit.
e3b0c442  
68beaabc  export interface MetricSample {
c9a93814  	ts: number;   // milliseconds since epoch (or relative; monotonic is fine)
c1482f21  	tokens: number;
d10b36aa  }
e3b0c442  
5e549d26  export interface MetricSnapshot {
e15bbae0  	[name: string]: number;
d10b36aa  }
e3b0c442  
171c5691  // A Prometheus metric line has the shape:
c1614804  //   name                     42.0
3f9c8e02  //   name{label="v",...}      42.0
8fdefbf2  //   name{labels} 42 <exemplar>
469ed1f9  // Comments start with # and are ignored. We capture: metric name (no labels
5d90e35a  // in the captured group) + value.
a2c23396  //
2ffdd54d  // The name pattern matches Prometheus naming rules: [a-zA-Z_:][a-zA-Z0-9_:]*
c108ae90  // with optional label brace block.
c31841fd  const METRIC_LINE = /^([a-zA-Z_:][a-zA-Z0-9_:]*)(?:\{[^}]*\})?\s+(\S+)(?:\s.*)?$/;
e3b0c442  
8d64a30d  /**
71f6083c   * Parse a Prometheus text-format body into a flat `{metric_name: value}` map.
64e75266   *
09d9f024   * - Ignores lines starting with `#` (HELP / TYPE / exemplar annotations).
29205fc5   * - Ignores empty lines.
accdb5ea   * - Skips lines whose value is not a finite number (e.g. `NaN`, `Inf`, `+Inf`).
41b7a466   * - For duplicate metric names (different labels), LAST one wins. This is
8329bbc3   *   acceptable for our use case because vLLM emits one labeled series per
72f5c8b2   *   model_name and we have a single model loaded.
533a9f11   */
64f5c2c3  export function parseMetrics(text: string): MetricSnapshot {
d2022afe  	const out: MetricSnapshot = {};
559e2dbf  	for (const line of text.split("\n")) {
70dcf75a  		const trimmed = line.trim();
4d61deab  		if (trimmed.length === 0) continue;
a96fef79  		if (trimmed.startsWith("#")) continue;
67457956  		const m = METRIC_LINE.exec(trimmed);
b9ab13f3  		if (!m) continue;
91452520  		const name = m[1];
a5d8400e  		const rawValue = m[2];
774f3062  		if (!name || !rawValue) continue;
9ebc051c  		const v = Number(rawValue);
cdd3ce83  		if (!Number.isFinite(v)) continue;
de335de9  		out[name] = v;
a32a3bb7  	}
547624f0  	return out;
d10b36aa  }
e3b0c442  
8d64a30d  /**
cbb27217   * Fetch `${baseUrl}/metrics` and parse the Prometheus-text response.
64e75266   *
360a2339   * @param baseUrl vLLM endpoint base URL (e.g. "http://127.0.0.1:8002"). A
79a024e3   *                trailing slash is tolerated.
fbc0b297   * @param timeoutMs Abort the fetch after this many ms (default 2000).
533a9f11   */
ce845a40  export async function fetchVllmMetrics(
3fc75565  	baseUrl: string,
00960a64  	timeoutMs = 2000,
36d212e5  ): Promise<MetricSnapshot> {
05cfb544  	const url = `${baseUrl.replace(/\/$/, "")}/metrics`;
9be17ea3  	const ctl = new AbortController();
9044f303  	const t = setTimeout(() => ctl.abort(), timeoutMs);
debaf31e  	try {
b3b74f27  		const resp = await fetch(url, { signal: ctl.signal });
b64dcd5f  		if (!resp.ok) throw new Error(`vllm /metrics returned status ${resp.status}`);
1b14387d  		const text = await resp.text();
e780ba49  		return parseMetrics(text);
bc9be798  	} finally {
f1cc0f51  		clearTimeout(t);
a32a3bb7  	}
d10b36aa  }
e3b0c442  
8d64a30d  /**
5165cae1   * Pure-function rate calculator over a sequence of `(ts, tokens)` samples.
64e75266   *
a63803c2   * rate = (lastTokens - firstTokens) / ((lastTs - firstTs) / 1000)   [tok/s]
64e75266   *
ffa17273   * Returns 0 on warmup (< 2 samples) or on degenerate zero-Δt windows.
533a9f11   */
5bade65e  export function computeTokRate(samples: MetricSample[]): number {
3c49c329  	if (samples.length < 2) return 0;
7cc1a015  	const first = samples[0]!;
6ec8caa2  	const last = samples[samples.length - 1]!;
5cbd25a6  	const dtSec = (last.ts - first.ts) / 1000;
ef5e65d4  	if (dtSec <= 0) return 0;
14f2f51d  	return (last.tokens - first.tokens) / dtSec;
d10b36aa  }
e3b0c442  
8d64a30d  /**
dcbc024d   * Stateful 5-second sliding-window rate tracker.
64e75266   *
76ece5ee   * Per Pitfall #6: the raw 1-second delta of `vllm:generation_tokens_total`
d8cfd445   * is noisy because completions bunch at request boundaries. A 5-sample
b16a70db   * window smooths out the signal without introducing meaningful lag at
631eca63   * the 1 Hz TUI-footer cadence.
64e75266   *
0fb3bd2b   * Window shape: entries older than `windowMs` (default 5000) are evicted
44a83e9d   * on every push() and every rate() call. This gives exactly the "last 5
e14e51cb   * seconds of samples" semantics the plan's Pitfall #6 guard specifies.
533a9f11   */
4b6be2cb  export class TokRateTracker {
5d909ea7  	private _samples: MetricSample[] = [];
edf40a1f  	private _windowMs: number;
e3b0c442  
045e2cd1  	constructor(windowMs = 5000) {
f388e1d2  		this._windowMs = windowMs;
a32a3bb7  	}
e3b0c442  
5eb8d077  	push(tokensTotal: number, nowMs: number = Date.now()): void {
fb46873f  		this._samples.push({ ts: nowMs, tokens: tokensTotal });
46ddf6b7  		this._prune(nowMs);
a32a3bb7  	}
e3b0c442  
9f4c6ac9  	rate(nowMs: number = Date.now()): number {
46ddf6b7  		this._prune(nowMs);
ca902f52  		return computeTokRate(this._samples);
a32a3bb7  	}
e3b0c442  
15364225  	samplesInWindow(): number {
e0b2dac1  		return this._samples.length;
a32a3bb7  	}
e3b0c442  
2b9e3092  	private _prune(nowMs: number): void {
ee8eca7b  		const cutoff = nowMs - this._windowMs;
4a9a0e99  		// Keep samples whose ts is strictly within the window (ts > cutoff).
c16dcbf2  		// Strict > means a sample exactly at ts=nowMs-windowMs is dropped —
04213559  		// matches the natural "older than 5s" test expectation.
001016da  		this._samples = this._samples.filter((s) => s.ts > cutoff);
a32a3bb7  	}
d10b36aa  }
